1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE = 60;
4	const COMPONENT_BASE = 25;
5	const FIRST_INS_SURCHARGE = 0.1;
6	const CURSE_SURCHARGE = 0.5;
7	const HIGH_ENCH_SURCHARGE = 0.3;
8	const HIGH_ENCH_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT = 0.2;
10	const LOYALTY_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	const DEDUCTIBLE = 100;
13	const HIGH_ENCH_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCH_CLAIM_FACTOR = 0.5;
15	const INSURANCE_VALUE_MULTIPLIER = 10;
16	
17	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	export type Item = {
29	  type: string;
30	  enchantment?: number;
31	  cursed?: boolean;
32	  material?: string;
33	};
34	
35	export type Customer = {
36	  yearsWithMHPCO?: number;
37	};
38	
39	export type QuoteInput = {
40	  customer?: Customer;
41	  items: Item[];
42	  isFollowUp?: boolean;
43	};
44	
45	export type QuoteResult = {
46	  premium: number;
47	};
48	
49	export type DamageEntry = {
50	  itemType: string;
51	  amount: number;
52	};
53	
54	export type Policy = {
55	  items: Item[];
56	  remainingCap: number;
57	};
58	
59	export type Incident = {
60	  cause?: string;
61	  damages: DamageEntry[];
62	};
63	
64	export type ClaimInput = {
65	  policy: Policy;
66	  incident: Incident;
67	};
68	
69	export type ClaimResult = {
70	  payout: number;
71	  remainingCap: number;
72	};
73	
74	export const insuranceValueFor = (item: Item): number =>
75	  (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0) * INSURANCE_VALUE_MULTIPLIER;
76	
77	const baseForItem = (item: Item): number =>
78	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
79	
80	const isComponent = (item: Item): boolean =>
81	  COMPONENT_TYPES.has(item.type);
82	
83	const itemModifierSum = (item: Item): number => {
84	  let mod = FIRST_INS_SURCHARGE;
85	  if (item.cursed) mod += CURSE_SURCHARGE;
86	  if ((item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD) mod += HIGH_ENCH_SURCHARGE;
87	  return mod;
88	};
89	
90	const itemCharge = (item: Item): number =>
91	  baseForItem(item) * (1 + itemModifierSum(item));
92	
93	const countByType = (items: Item[]): Record<string, number> => {
94	  const counts: Record<string, number> = {};
95	  for (const item of items) {
96	    counts[item.type] = (counts[item.type] ?? 0) + 1;
97	  }
98	  return counts;
99	};
100	
101	const componentsCharge = (items: Item[]): number => {
102	  const componentItems = items.filter(isComponent);
103	  const counts = countByType(componentItems);
104	  let total = 0;
105	  for (const type in counts) {
106	    const count = counts[type];
107	    if (count === BLOCK_SIZE) {
108	      total += BLOCK_PRICE * (1 + FIRST_INS_SURCHARGE);
109	    } else {
110	      total += count * COMPONENT_BASE * (1 + FIRST_INS_SURCHARGE);
111	    }
112	  }
113	  return total;
114	};
115	
116	const componentsBase = (items: Item[]): number => {
117	  const componentItems = items.filter(isComponent);
118	  const counts = countByType(componentItems);
119	  let total = 0;
120	  for (const type in counts) {
121	    const count = counts[type];
122	    total += count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_BASE;
123	  }
124	  return total;
125	};
126	
127	const nonComponentsCharge = (items: Item[]): number =>
128	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + itemCharge(item), 0);
129	
130	const nonComponentsBase = (items: Item[]): number =>
131	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);
132	
133	export function quote(input: QuoteInput): QuoteResult {
134	  const items = input.items;
135	  const itemTotal = nonComponentsCharge(items) + componentsCharge(items);
136	  const policyBase = nonComponentsBase(items) + componentsBase(items);
137	  const years = input.customer?.yearsWithMHPCO ?? 0;
138	  let policyModifiers = 0;
139	  if (years >= LOYALTY_THRESHOLD) policyModifiers -= LOYALTY_DISCOUNT;
140	  if (input.isFollowUp) policyModifiers -= FOLLOW_UP_DISCOUNT;
141	  const policyAdjustment = policyBase * policyModifiers;
142	  const raw = itemTotal + policyAdjustment + PROCESSING_FEE;
143	  const premium = Math.ceil(Math.round(raw * 1e8) / 1e8);
144	  return { premium };
145	}
146	
147	export function claim(input: ClaimInput): ClaimResult {
148	  let payout = 0;
149	  for (const damageEntry of input.incident.damages) {
150	    const item = input.policy.items.find((i) => i.type === damageEntry.itemType);
151	    let amount = damageEntry.amount;
152	    if (item && (item.enchantment ?? 0) >= HIGH_ENCH_CLAIM_THRESHOLD) {
153	      amount = amount * HIGH_ENCH_CLAIM_FACTOR;
154	    }
155	    payout += amount - DEDUCTIBLE;
156	  }
157	  payout = Math.min(payout, input.policy.remainingCap);
158	  const remainingCap = input.policy.remainingCap - payout;
159	  return { payout, remainingCap };
160	}
