1	import {
2	  quote,
3	  claim,
4	  insuranceValueFor,
5	  type Customer,
6	  type Item,
7	  type Policy,
8	  type Incident,
9	} from "./claim-office.js";
10	
11	const CAP_MULTIPLIER = 2;
12	
13	type QuoteStep = {
14	  op: "quote";
15	  items: Item[];
16	};
17	
18	type ClaimStep = {
19	  op: "claim";
20	  policy: number;
21	  incident: Incident;
22	};
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	type Scenario = {
27	  customer: Customer;
28	  steps: Step[];
29	};
30	
31	const readStdin = async (): Promise<string> => {
32	  const chunks: Buffer[] = [];
33	  for await (const chunk of process.stdin) {
34	    chunks.push(chunk as Buffer);
35	  }
36	  return Buffer.concat(chunks).toString("utf8");
37	};
38	
39	const policyCapFor = (items: Item[]): number =>
40	  items.reduce((sum, item) => sum + CAP_MULTIPLIER * insuranceValueFor(item), 0);
41	
42	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
43	
44	const handleQuote = (
45	  customer: Customer,
46	  step: QuoteStep,
47	  policies: Policy[],
48	): unknown => {
49	  for (const item of step.items) {
50	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
51	      throw new Error(`Unknown item type: ${item.type}`);
52	    }
53	  }
54	  const result = quote({ customer, items: step.items });
55	  policies.push({ items: step.items, remainingCap: policyCapFor(step.items) });
56	  return result;
57	};
58	
59	const handleClaim = (step: ClaimStep, policies: Policy[]): unknown => {
60	  const policy = policies[step.policy];
61	  const result = claim({ policy, incident: step.incident });
62	  policy.remainingCap = result.remainingCap;
63	  return result;
64	};
65	
66	const runStep = (
67	  customer: Customer,
68	  step: Step,
69	  policies: Policy[],
70	): unknown =>
71	  step.op === "quote"
72	    ? handleQuote(customer, step, policies)
73	    : handleClaim(step, policies);
74	
75	const runScenario = (scenario: Scenario): unknown[] => {
76	  const policies: Policy[] = [];
77	  return scenario.steps.map((step) => runStep(scenario.customer, step, policies));
78	};
79	
80	const main = async () => {
81	  const input = await readStdin();
82	  const scenario: Scenario = JSON.parse(input);
83	  const results = runScenario(scenario);
84	  process.stdout.write(JSON.stringify({ results }));
85	};
86	
87	main().catch((err) => {
88	  process.stderr.write(String(err));
89	  process.exit(1);
90	});
